const { Storage } = require('@google-cloud/storage');
const express = require('express');
const app = express();
const storage = new Storage();

app.get('/files', async (req, res) => {
    const bucketName = req.query.bucket;
    const filePath = req.query.path;

    if (!bucketName || !filePath) {
        return res.status(400).send('Bucket and file path are required.');
    }

    // Validate bucket name and file path to prevent directory traversal attacks
    const sanitizedBucketName = bucketName.replace(/[^a-zA-Z0-9-_]/g, '');
    const sanitizedFilePath = filePath.replace(/(\.\.\/|\/)/g, '');

    const file = storage.bucket(sanitizedBucketName).file(sanitizedFilePath);

    try {
        const [exists] = await file.exists();
        if (!exists) {
            return res.status(404).send('File not found.');
        }

        res.set('Content-Type', 'application/octet-stream');
        file.createReadStream().pipe(res);
    } catch (error) {
        console.error(error);
        res.status(500).send('Internal Server Error');
    }
});

exports.fileServingFunction = app;